  297: static void
  298: xfs_buf_free_callback(
  299: 	struct callback_head	*cb)
  300: {
  301: 	struct xfs_buf		*bp = container_of(cb, struct xfs_buf, b_rcu);
  302: 
  303: 	xfs_buf_free_maps(bp);
  304: 	kmem_cache_free(xfs_buf_cache, bp);
