  351: static unsigned int
  352: xfs_attr_filter(
  353: 	u32			ioc_flags)
  354: {
  355: 	if (ioc_flags & XFS_IOC_ATTR_ROOT)
  356: 		return XFS_ATTR_ROOT;
  357: 	if (ioc_flags & XFS_IOC_ATTR_SECURE)
  358: 		return XFS_ATTR_SECURE;
  359: 	return 0;
  360: }
