 1303: 	/*
 1304: 	 * Lock the primary superblock buffer to serialize all callers that
 1305: 	 * are trying to set feature bits.
 1306: 	 */
 1307: 	xfs_buf_lock(mp->m_sb_bp);
 1308: 	xfs_buf_hold(mp->m_sb_bp);
 1309: 
 1310: 	if (xfs_is_shutdown(mp)) {
