 1320: 	 * the log_incompat bit to be set in the primary super now to protect
 1321: 	 * the log items that we're going to commit later.
 1322: 	 */
 1323: 	dsb = mp->m_sb_bp->b_addr;
 1324: 	xfs_sb_to_disk(dsb, &mp->m_sb);
