   96: 		return 0;
>  97: 	if (error) {
   98: 		notify->want_shutdown = true;
   99: 		return 0;
  100: 	}
  101: 
  102: 	mapping = VFS_I(ip)->i_mapping;
  103: 	pgoff = xfs_failure_pgoff(mp, rec, notify);
  104: 	pgcnt = xfs_failure_pgcnt(mp, rec, notify);
