   99: int
  100: xfs_readlink(
  101: 	struct xfs_inode	*ip,
  102: 	char			*link)
  103: {
  104: 	struct xfs_mount	*mp = ip->i_mount;
  105: 	xfs_fsize_t		pathlen;
  106: 	int			error = -EFSCORRUPTED;
  107: 
  108: 	trace_xfs_readlink(ip);
  109: 
  110: 	if (xfs_is_shutdown(mp))
  111: 		return -EIO;
  112: 	if (xfs_ifork_zapped(ip, XFS_DATA_FORK))
  113: 		return -EIO;
  114: 
  115: 	xfs_ilock(ip, XFS_ILOCK_SHARED);
  116: 
  117: 	pathlen = ip->i_disk_size;
  118: 	if (!pathlen)
  119: 		goto out;
  120: 
  121: 	if (pathlen < 0 || pathlen > XFS_SYMLINK_MAXLEN) {
  122: 		xfs_alert(mp, "%s: inode (%llu) bad symlink length (%lld)",
  123: 			 __func__, (unsigned long long) ip->i_ino,
  124: 			 (long long) pathlen);
  125: 		ASSERT(0);
  126: 		goto out;
  127: 	}
  128: 
  129: 	if (ip->i_df.if_format == XFS_DINODE_FMT_LOCAL) {
  130: 		/*
> 131: 		 * The VFS crashes on a NULL pointer, so return -EFSCORRUPTED
  132: 		 * if if_data is junk.
  133: 		 */
  134: 		if (XFS_IS_CORRUPT(ip->i_mount, !ip->i_df.if_data))
  135: 			goto out;
  136: 
  137: 		memcpy(link, ip->i_df.if_data, pathlen + 1);
  138: 		error = 0;
  139: 	} else {
  140: 		error = xfs_readlink_bmap_ilocked(ip, link);
  141: 	}
  142: 
  143:  out:
  144: 	xfs_iunlock(ip, XFS_ILOCK_SHARED);
  145: 	return error;
  146: }
