  148: int
  149: xfs_symlink(
  150: 	struct mnt_idmap	*idmap,
  151: 	struct xfs_inode	*dp,
  152: 	struct xfs_name		*link_name,
  153: 	const char		*target_path,
  154: 	umode_t			mode,
  155: 	struct xfs_inode	**ipp)
  156: {
  157: 	struct xfs_mount	*mp = dp->i_mount;
  158: 	struct xfs_trans	*tp = NULL;
  159: 	struct xfs_inode	*ip = NULL;
  160: 	int			error = 0;
