  173: 	struct xfs_dquot	*udqp = NULL;
  174: 	struct xfs_dquot	*gdqp = NULL;
  175: 	struct xfs_dquot	*pdqp = NULL;
  176: 	uint			resblks;
  177: 	xfs_ino_t		ino;
  178: 
  179: 	*ipp = NULL;
  180: 
  181: 	trace_xfs_symlink(dp, link_name);
  182: 
  183: 	if (xfs_is_shutdown(mp))
  184: 		return -EIO;
  185: 
  186: 	/*
  187: 	 * Check component lengths of the target path name.
  188: 	 */
  189: 	pathlen = strlen(target_path);
  190: 	if (pathlen >= XFS_SYMLINK_MAXLEN)      /* total string too long */
  191: 		return -ENAMETOOLONG;
  192: 	ASSERT(pathlen > 0);
  193: 
  194: 	prid = xfs_get_initial_prid(dp);
  195: 
  196: 	/*
  197: 	 * Make sure that we have allocated dquot(s) on disk.
  198: 	 */
  199: 	error = xfs_qm_vop_dqalloc(dp, mapped_fsuid(idmap, &init_user_ns),
  200: 			mapped_fsgid(idmap, &init_user_ns), prid,
  201: 			XFS_QMOPT_QUOTALL | XFS_QMOPT_INHERIT,
  202: 			&udqp, &gdqp, &pdqp);
  203: 	if (error)
  204: 		return error;
  205: 
  206: 	/*
  207: 	 * The symlink will fit into the inode data fork?
  208: 	 * There can't be any attributes so we get the whole variable part.
  209: 	 */
  210: 	if (pathlen <= XFS_LITINO(mp))
  211: 		fs_blocks = 0;

  205: 	}
